-- ----------------------------------------------------------------------------
-- SymmetryGroups: The wallpaper symmetry groups a tiling can belong to.
-- ----------------------------------------------------------------------------
CREATE TABLE symmetry_groups (
  symmetry_group_id                   TEXT                 PRIMARY KEY,         -- Stable id (IUC short notation, slugified).
  notation                            TEXT                ,                     -- IUC / crystallographic short notation (e.g. 'p6m').
  orbifold                            TEXT                ,                     -- Conway orbifold notation (e.g. '*632').
  display_name                        TEXT                ,                     -- Human-friendly name.
  description                         TEXT                ,                     -- What this wallpaper group is.
  lattice_type                        TEXT                ,                     -- Bravais lattice class: oblique | rectangular | rhombic | square | hexagonal.
  lattice_angle_deg                   NUMERIC             ,                     -- Angle (deg) between the two lattice basis vectors B1,B2.
  lattice_ratio                       NUMERIC             ,                     -- Length ratio |B2|/|B1| of the lattice basis.
  generators                          TEXT                ,                     -- JSON array of non-identity coset-rep affine ops in fractional coords: {k,m:[a,b,c,d],t:[tx,ty]} mapping (u,v)->(a u+b v+tx, c u+d v+ty).
  rotation_order                      INTEGER             ,                     -- Highest order of rotational symmetry (1,2,3,4,6).
  operation_count                     INTEGER             ,                     -- Number of point-group coset reps including the identity (= motif copies per lattice cell).
  has_mirrors                         BOOLEAN             ,                     -- Whether the group contains reflection (mirror) symmetry.
  has_glides                          BOOLEAN                                   -- Whether the group contains glide-reflection symmetry.
);
COMMENT ON TABLE symmetry_groups IS 'The wallpaper symmetry groups a tiling can belong to.';
COMMENT ON COLUMN symmetry_groups.symmetry_group_id IS 'Stable id (IUC short notation, slugified).';
COMMENT ON COLUMN symmetry_groups.notation IS 'IUC / crystallographic short notation (e.g. ''p6m'').';
COMMENT ON COLUMN symmetry_groups.orbifold IS 'Conway orbifold notation (e.g. ''*632'').';
COMMENT ON COLUMN symmetry_groups.display_name IS 'Human-friendly name.';
COMMENT ON COLUMN symmetry_groups.description IS 'What this wallpaper group is.';
COMMENT ON COLUMN symmetry_groups.lattice_type IS 'Bravais lattice class: oblique | rectangular | rhombic | square | hexagonal.';
COMMENT ON COLUMN symmetry_groups.lattice_angle_deg IS 'Angle (deg) between the two lattice basis vectors B1,B2.';
COMMENT ON COLUMN symmetry_groups.lattice_ratio IS 'Length ratio |B2|/|B1| of the lattice basis.';
COMMENT ON COLUMN symmetry_groups.generators IS 'JSON array of non-identity coset-rep affine ops in fractional coords: {k,m:[a,b,c,d],t:[tx,ty]} mapping (u,v)->(a u+b v+tx, c u+d v+ty).';
COMMENT ON COLUMN symmetry_groups.rotation_order IS 'Highest order of rotational symmetry (1,2,3,4,6).';
COMMENT ON COLUMN symmetry_groups.operation_count IS 'Number of point-group coset reps including the identity (= motif copies per lattice cell).';
COMMENT ON COLUMN symmetry_groups.has_mirrors IS 'Whether the group contains reflection (mirror) symmetry.';
COMMENT ON COLUMN symmetry_groups.has_glides IS 'Whether the group contains glide-reflection symmetry.';

-- ----------------------------------------------------------------------------
-- Prototiles: The prototiles (regular polygons) available for tilings.
-- ----------------------------------------------------------------------------
CREATE TABLE prototiles (
  prototile_id                        TEXT                 PRIMARY KEY,         -- Stable id.
  display_name                        TEXT                ,                     -- Human name (e.g. 'Equilateral Triangle').
  sides                               INTEGER             ,                     -- Number of edges of this regular polygon.
  edge_length                         NUMERIC                                   -- Edge length in unit cells (1.0 = unit edge).
);
COMMENT ON TABLE prototiles IS 'The prototiles (regular polygons) available for tilings.';
COMMENT ON COLUMN prototiles.prototile_id IS 'Stable id.';
COMMENT ON COLUMN prototiles.display_name IS 'Human name (e.g. ''Equilateral Triangle'').';
COMMENT ON COLUMN prototiles.sides IS 'Number of edges of this regular polygon.';
COMMENT ON COLUMN prototiles.edge_length IS 'Edge length in unit cells (1.0 = unit edge).';

-- ----------------------------------------------------------------------------
-- Tilings: Catalogued tilings of the plane.
-- ----------------------------------------------------------------------------
CREATE TABLE tilings (
  tiling_id                           TEXT                 PRIMARY KEY,         -- Stable id.
  display_name                        TEXT                ,                     -- Human name (e.g. 'Hexagonal tiling').
  vertex_config                       TEXT                ,                     -- Vertex configuration / Schlafli symbol string (e.g. '3.4.6.4').
  kind                                TEXT                ,                     -- 'regular' | 'semiregular' (Archimedean).
  is_edge_to_edge                     BOOLEAN             ,                     -- Whether tiles meet edge-to-edge.
  symmetry_group                      TEXT                ,                     -- The wallpaper symmetry group of this tiling.
  t1x                                 NUMERIC             ,                     -- X component of the first lattice translation vector (unit cells). Repeating the fundamental domain along T1 and T2 fills the plane.
  t1y                                 NUMERIC             ,                     -- Y component of the first lattice translation vector (unit cells).
  t2x                                 NUMERIC             ,                     -- X component of the second lattice translation vector (unit cells).
  t2y                                 NUMERIC                                   -- Y component of the second lattice translation vector (unit cells).
);
COMMENT ON TABLE tilings IS 'Catalogued tilings of the plane.';
COMMENT ON COLUMN tilings.tiling_id IS 'Stable id.';
COMMENT ON COLUMN tilings.display_name IS 'Human name (e.g. ''Hexagonal tiling'').';
COMMENT ON COLUMN tilings.vertex_config IS 'Vertex configuration / Schlafli symbol string (e.g. ''3.4.6.4'').';
COMMENT ON COLUMN tilings.kind IS '''regular'' | ''semiregular'' (Archimedean).';
COMMENT ON COLUMN tilings.is_edge_to_edge IS 'Whether tiles meet edge-to-edge.';
COMMENT ON COLUMN tilings.symmetry_group IS 'The wallpaper symmetry group of this tiling.';
COMMENT ON COLUMN tilings.t1x IS 'X component of the first lattice translation vector (unit cells). Repeating the fundamental domain along T1 and T2 fills the plane.';
COMMENT ON COLUMN tilings.t1y IS 'Y component of the first lattice translation vector (unit cells).';
COMMENT ON COLUMN tilings.t2x IS 'X component of the second lattice translation vector (unit cells).';
COMMENT ON COLUMN tilings.t2y IS 'Y component of the second lattice translation vector (unit cells).';

-- ----------------------------------------------------------------------------
-- TilingPrototiles: First-class junction: prototiles used by each tiling.
-- ----------------------------------------------------------------------------
CREATE TABLE tiling_prototiles (
  tiling_prototile_id                 TEXT                 PRIMARY KEY,         -- Stable id.
  tiling                              TEXT                ,                     -- The tiling.
  prototile                           TEXT                ,                     -- A prototile used by that tiling.
  count_at_vertex                     INTEGER                                   -- How many of this prototile meet at a typical vertex.
);
COMMENT ON TABLE tiling_prototiles IS 'First-class junction: prototiles used by each tiling.';
COMMENT ON COLUMN tiling_prototiles.tiling_prototile_id IS 'Stable id.';
COMMENT ON COLUMN tiling_prototiles.tiling IS 'The tiling.';
COMMENT ON COLUMN tiling_prototiles.prototile IS 'A prototile used by that tiling.';
COMMENT ON COLUMN tiling_prototiles.count_at_vertex IS 'How many of this prototile meet at a typical vertex.';

-- ----------------------------------------------------------------------------
-- VertexFigures: First-class vertex figures; validity derived from angle sum = 360.
-- ----------------------------------------------------------------------------
CREATE TABLE vertex_figures (
  vertex_figure_id                    TEXT                 PRIMARY KEY,         -- Stable id.
  tiling                              TEXT                ,                     -- The tiling this vertex figure belongs to.
  config                              TEXT                ,                     -- Vertex configuration at this vertex (e.g. '3.4.6.4').
  angle_sum_deg                       NUMERIC                                   -- Sum of interior angles meeting at this vertex (degrees).
);
COMMENT ON TABLE vertex_figures IS 'First-class vertex figures; validity derived from angle sum = 360.';
COMMENT ON COLUMN vertex_figures.vertex_figure_id IS 'Stable id.';
COMMENT ON COLUMN vertex_figures.tiling IS 'The tiling this vertex figure belongs to.';
COMMENT ON COLUMN vertex_figures.config IS 'Vertex configuration at this vertex (e.g. ''3.4.6.4'').';
COMMENT ON COLUMN vertex_figures.angle_sum_deg IS 'Sum of interior angles meeting at this vertex (degrees).';

-- ----------------------------------------------------------------------------
-- Regions: Bounded patches of the plane to be tiled.
-- ----------------------------------------------------------------------------
CREATE TABLE regions (
  region_id                           TEXT                 PRIMARY KEY,         -- Stable id.
  display_name                        TEXT                ,                     -- Human name.
  width                               NUMERIC             ,                     -- Region width in unit cells.
  height                              NUMERIC             ,                     -- Region height in unit cells.
  target_tiling                       TEXT                                      -- Which catalogued tiling this region is trying to realize.
);
COMMENT ON TABLE regions IS 'Bounded patches of the plane to be tiled.';
COMMENT ON COLUMN regions.region_id IS 'Stable id.';
COMMENT ON COLUMN regions.display_name IS 'Human name.';
COMMENT ON COLUMN regions.width IS 'Region width in unit cells.';
COMMENT ON COLUMN regions.height IS 'Region height in unit cells.';
COMMENT ON COLUMN regions.target_tiling IS 'Which catalogued tiling this region is trying to realize.';

-- ----------------------------------------------------------------------------
-- Placements: Individual tile placements within a region.
-- ----------------------------------------------------------------------------
CREATE TABLE placements (
  placement_id                        TEXT                 PRIMARY KEY,         -- Stable id.
  region                              TEXT                ,                     -- The region this tile is placed in.
  prototile                           TEXT                ,                     -- The prototile being placed.
  x                                   NUMERIC             ,                     -- X coordinate of the tile's anchor (unit cells).
  y                                   NUMERIC             ,                     -- Y coordinate of the tile's anchor (unit cells).
  rotation_deg                        NUMERIC             ,                     -- Rotation of the tile in degrees.
  is_overlapping                      BOOLEAN                                   -- Flag: this placement overlaps a neighbour (authored/validated).
);
COMMENT ON TABLE placements IS 'Individual tile placements within a region.';
COMMENT ON COLUMN placements.placement_id IS 'Stable id.';
COMMENT ON COLUMN placements.region IS 'The region this tile is placed in.';
COMMENT ON COLUMN placements.prototile IS 'The prototile being placed.';
COMMENT ON COLUMN placements.x IS 'X coordinate of the tile''s anchor (unit cells).';
COMMENT ON COLUMN placements.y IS 'Y coordinate of the tile''s anchor (unit cells).';
COMMENT ON COLUMN placements.rotation_deg IS 'Rotation of the tile in degrees.';
COMMENT ON COLUMN placements.is_overlapping IS 'Flag: this placement overlaps a neighbour (authored/validated).';

-- ----------------------------------------------------------------------------
-- WallpaperDesigns: User-authored wallpaper designs: a fundamental-domain motif (drawn strokes) replicated under a chosen symmetry group.
-- ----------------------------------------------------------------------------
CREATE TABLE wallpaper_designs (
  wallpaper_design_id                 TEXT                 PRIMARY KEY,         -- Stable id.
  display_name                        TEXT                ,                     -- Human name for this design.
  symmetry_group                      TEXT                ,                     -- The wallpaper group whose symmetry replicates the motif.
  strokes                             TEXT                ,                     -- JSON array of polylines drawn in the fundamental domain, in fractional cell coords: [{color,width,points:[[u,v],...]},...].
  stroke_color                        TEXT                ,                     -- Default stroke color (hex) for new strokes.
  background_color                    TEXT                                      -- Fill color (hex) behind the tiling.
);
COMMENT ON TABLE wallpaper_designs IS 'User-authored wallpaper designs: a fundamental-domain motif (drawn strokes) replicated under a chosen symmetry group.';
COMMENT ON COLUMN wallpaper_designs.wallpaper_design_id IS 'Stable id.';
COMMENT ON COLUMN wallpaper_designs.display_name IS 'Human name for this design.';
COMMENT ON COLUMN wallpaper_designs.symmetry_group IS 'The wallpaper group whose symmetry replicates the motif.';
COMMENT ON COLUMN wallpaper_designs.strokes IS 'JSON array of polylines drawn in the fundamental domain, in fractional cell coords: [{color,width,points:[[u,v],...]},...].';
COMMENT ON COLUMN wallpaper_designs.stroke_color IS 'Default stroke color (hex) for new strokes.';
COMMENT ON COLUMN wallpaper_designs.background_color IS 'Fill color (hex) behind the tiling.';

